class Solution:
    def countSmaller(self, nums: list[int]) -> list[int]:
        n = len(nums)
        if n == 0:
            return []

        indexed_nums = []
        for i in range(n):
            indexed_nums.append((nums[i], i))

        self.results = [0] * n

        self._merge_sort(indexed_nums)

        return self.results

    def _merge_sort(self, indexed_nums: list[tuple[int, int]]) -> list[tuple[int, int]]:
        n = len(indexed_nums)
        if n <= 1:
            return indexed_nums

        mid = n // 2
        left_half = self._merge_sort(indexed_nums[:mid])
        right_half = self._merge_sort(indexed_nums[mid:])

        return self._merge(left_half, right_half)

    def _merge(self, left_half: list[tuple[int, int]], right_half: list[tuple[int, int]]) -> list[tuple[int, int]]:
        merged = []
        i, j = 0, 0
        right_smaller_count = 0 

        while i < len(left_half) and j < len(right_half):
            left_val, left_original_idx = left_half[i]
            right_val, right_original_idx = right_half[j]

            if left_val <= right_val:
                self.results[left_original_idx] += right_smaller_count
                merged.append(left_half[i])
                i += 1
            else:
                merged.append(right_half[j])
                right_smaller_count += 1
                j += 1

        while i < len(left_half):
            left_val, left_original_idx = left_half[i]
            self.results[left_original_idx] += right_smaller_count
            merged.append(left_half[i])
            i += 1

        while j < len(right_half):
            merged.append(right_half[j])
            j += 1

        return merged
